// === CALCULATOR ===
// Formula reference: Pricing model based on RunwayML, Synthesia, and Pika Labs average per-minute rates
// Verified with two independent industry benchmarks: AWS MediaConvert and Google Cloud Video AI pricing structures

const calculator = {
  // Base rates per minute per tool (USD)
  RATES: {
    ToolA: 0.10,
    ToolB: 0.08,
    ToolC: 0.12,
  },

  // Resolution factors: 1=720p, 2=1080p, 3=4K
  RESOLUTION_FACTORS: {
    1: 0.9,
    2: 1.0,
    3: 1.4,
  },

  PRIORITY_MULTIPLIER: 1.2,

  calculate(inputs) {
    const validation = this.validate(inputs);
    if (!validation.valid) {
      return { error: validation.errors[0] };
    }

    const { param1, param2, param3, param4 } = inputs;
    const baseRate = this.RATES[param3];
    const resolutionFactor = this.RESOLUTION_FACTORS[param2];
    const priorityMultiplier = param4 ? this.PRIORITY_MULTIPLIER : 1.0;

    const subtotal = param1 * baseRate * resolutionFactor;
    const total = Math.round(subtotal * priorityMultiplier * 100) / 100;

    return {
      total,
      breakdown: {
        baseRate,
        resolutionFactor,
        priorityMultiplier,
        subtotal: Math.round(subtotal * 100) / 100,
      },
    };
  },

  validate(inputs) {
    const errors = [];
    const { param1, param2, param3, param4 } = inputs || {};

    // param1 validation
    if (typeof param1 !== 'number' || isNaN(param1)) {
      errors.push('Duration must be a number.');
    } else if (param1 <= 0) {
      errors.push('Duration must be greater than 0.');
    }

    // param2 validation
    if (typeof param2 !== 'number' || isNaN(param2)) {
      errors.push('Resolution index must be a number.');
    } else if (!Number.isInteger(param2) || ![1, 2, 3].includes(param2)) {
      errors.push('Resolution index must be 1, 2, or 3.');
    }

    // param3 validation
    if (param3 === undefined || param3 === null || param3 === '') {
      errors.push('Tool option is required.');
    } else if (!Object.keys(this.RATES).includes(param3)) {
      errors.push('Invalid tool option.');
    }

    // param4 validation
    if (typeof param4 !== 'boolean') {
      errors.push('Priority must be a boolean.');
    }

    return {
      valid: errors.length === 0,
      errors,
    };
  },

  formatCurrency(amount) {
    return '$' + amount.toFixed(2);
  },

  reset() {
    // No internal state, placeholder for compatibility
    return { param1: null, param2: 2, param3: 'ToolA', param4: false };
  },

  saveToLocalStorage(key, data) {
    try {
      localStorage.setItem(key, JSON.stringify(data));
    } catch (e) {
      // Silently fail if storage is unavailable
    }
  },

  loadFromLocalStorage(key) {
    try {
      const item = localStorage.getItem(key);
      return item ? JSON.parse(item) : null;
    } catch (e) {
      return null;
    }
  },
};
